/**
 * Poisson log-linear GLM.
 * log(lambda[i]) = alpha + beta * x[i]
 * Parameters: alpha (log-scale intercept), beta (log-scale slope).
 */
export const defaultModel3 = `model {
  for (i in 1:N) {
    count[i] ~ dpois(lambda[i])
    log(lambda[i]) <- alpha + beta * x[i]
  }
  alpha ~ dnorm(0, 0.04)
  beta ~ dnorm(0, 0.04)
}`;

